export const body = "\n\n<!-- Top bar -->\n<header class=\"ss-bar\">\n  <div class=\"ss-bar__inner\">\n    <div class=\"ss-bar__brand\">\n      <a class=\"ss-bar__logo\" href=\"/\"><img src=\"/logo-full.jpg\" alt=\"EuroMedPartner\"></a>\n      <span class=\"ss-bar__divider\"></span>\n      <span class=\"ss-bar__band\">\n        <span class=\"ss-bar__band-tag\">Bando attivo</span>\n        <span class=\"ss-bar__band-name\">Smart<span class=\"accent\">&amp;</span>Start <span class=\"accent\">Italia</span></span>\n      </span>\n    </div>\n    <nav class=\"ss-bar__steps\" aria-label=\"Progresso funnel\"><a class=\"ss-step ss-step--done\" href=\"/\"><span class=\"ss-step__num\">01</span><span class=\"ss-step__label\">Diagnosi</span></a><a class=\"ss-step ss-step--done\" href=\"/quiz\"><span class=\"ss-step__num\">02</span><span class=\"ss-step__label\">Quiz</span></a><a class=\"ss-step ss-step--done\" href=\"/optin\"><span class=\"ss-step__num\">03</span><span class=\"ss-step__label\">Profilo</span></a><a class=\"ss-step ss-step--current\" href=\"/booking\"><span class=\"ss-step__num\">04</span><span class=\"ss-step__label\">Call</span></a></nav>\n    <div></div>\n  </div>\n  <div class=\"ss-bar__progress\"><div class=\"ss-bar__progress-track\"></div><div class=\"ss-bar__progress-fill\" style=\"width:100%\"></div></div>\n</header>\n\n<!-- ============ TOP ============ -->\n<section class=\"bk-top\">\n  <div class=\"bk-top__inner\">\n    <div class=\"bk-top__tag\">Step finale · Prenota la call</div>\n    <h1 class=\"bk-top__title\">Diagnosi pronta.<br>Resta solo da fissare <span class=\"accent\">l'orario</span>.</h1>\n    <p class=\"bk-top__lede\"><strong>Trenta minuti</strong> con un EU Project Manager per discutere i bandi compatibili con il tuo progetto, validare l'idea progettuale e definire il percorso di candidatura. Senza impegno.</p>\n  </div>\n</section>\n\n<!-- ============ BOOKING GRID ============ -->\n<section class=\"bk-grid\">\n\n  <!-- MAIN -->\n  <div class=\"bk-main\">\n\n    <!-- Calendar -->\n    <div class=\"cal\" id=\"cal\">\n      <div class=\"cal__profile\">\n        <div class=\"cal__avatar\"><img src=\"/team/maria.jpg\" alt=\"Maria Elena Oddo\"></div>\n        <div class=\"cal__name\">Maria Elena Oddo</div>\n        <div class=\"cal__role\">EU Project Manager</div>\n        <h2 class=\"cal__title\">Diagnosi finanza agevolata</h2>\n        <p class=\"cal__desc\">30 minuti per analizzare insieme il tuo progetto, i bandi compatibili e definire il percorso di candidatura.</p>\n        <div class=\"cal__meta\">\n          <div class=\"cal__meta-row\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 6v6l4 2\"/></svg>\n            <span>30 minuti</span>\n          </div>\n          <div class=\"cal__meta-row\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"2\" y=\"6\" width=\"20\" height=\"12\" rx=\"2\"/><path d=\"M2 12h20\"/></svg>\n            <span>Google Meet · link via email</span>\n          </div>\n          <div class=\"cal__meta-row\">\n            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M16 2v4M8 2v4M3 10h18\"/></svg>\n            <span>Fuso orario: Europe/Rome</span>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"cal__date-picker\">\n        <div class=\"cal__month-bar\">\n          <div class=\"cal__month\" id=\"calMonth\">Giugno 2026</div>\n          <div class=\"cal__month-nav\">\n            <button aria-label=\"Mese precedente\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"m15 18-6-6 6-6\"/></svg></button>\n            <button aria-label=\"Mese successivo\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"m9 18 6-6-6-6\"/></svg></button>\n          </div>\n        </div>\n        <div class=\"cal__weekdays\">\n          <div class=\"cal__weekday\">Lun</div>\n          <div class=\"cal__weekday\">Mar</div>\n          <div class=\"cal__weekday\">Mer</div>\n          <div class=\"cal__weekday\">Gio</div>\n          <div class=\"cal__weekday\">Ven</div>\n          <div class=\"cal__weekday\">Sab</div>\n          <div class=\"cal__weekday\">Dom</div>\n        </div>\n        <div class=\"cal__days\" id=\"calDays\"></div>\n\n        <div class=\"cal__slots\" id=\"calSlots\" style=\"display:none\">\n          <div class=\"cal__slots-label\">Orari disponibili <span id=\"calSlotsDate\" style=\"color:var(--emp-ink);font-weight:600;text-transform:none;letter-spacing:0\"></span></div>\n          <div class=\"cal__slots-grid\" id=\"calSlotsGrid\"></div>\n        </div>\n      </div>\n    </div>\n\n  </div>\n\n  <!-- STICKY RIGHT -->\n  <aside class=\"bk-sticky\">\n    <div class=\"bk-summary\">\n      <div class=\"bk-summary__inner\">\n        <div class=\"bk-summary__label\">Il tuo appuntamento</div>\n        <h3 class=\"bk-summary__title\">Diagnosi finanza agevolata</h3>\n\n        <div class=\"bk-summary__row\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 6v6l4 2\"/></svg>\n          <span><strong>30 minuti</strong>Call gratuita · no impegno</span>\n        </div>\n        <div class=\"bk-summary__row\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2\"/><circle cx=\"12\" cy=\"7\" r=\"4\"/></svg>\n          <span><strong>Con Maria Elena Oddo</strong>EU Project Manager</span>\n        </div>\n        <div class=\"bk-summary__row\" id=\"rowDate\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><path d=\"M16 2v4M8 2v4M3 10h18\"/></svg>\n          <span><strong>Data e ora</strong>Seleziona dal calendario</span>\n        </div>\n        <div class=\"bk-summary__row\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72c.13.96.36 1.9.7 2.81a2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.91.34 1.85.57 2.81.7A2 2 0 0 1 22 16.92Z\"/></svg>\n          <span><strong>Google Meet</strong>Link inviato via email</span>\n        </div>\n\n        <a href=\"#cal\" class=\"bk-summary__cta\" id=\"confirmBtn\">Conferma appuntamento</a>\n      </div>\n    </div>\n\n    <div class=\"bk-incl\">\n      <div class=\"bk-incl__label\">Cosa è incluso</div>\n      <div class=\"bk-incl__list\">\n        <div class=\"bk-incl__item\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 6 9 17l-5-5\"/></svg>\n          <span>Analisi della tua idea progettuale</span>\n        </div>\n        <div class=\"bk-incl__item\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 6 9 17l-5-5\"/></svg>\n          <span>Mappa dei bandi compatibili attivi</span>\n        </div>\n        <div class=\"bk-incl__item\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 6 9 17l-5-5\"/></svg>\n          <span>Stima del contributo ottenibile</span>\n        </div>\n        <div class=\"bk-incl__item\">\n          <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 6 9 17l-5-5\"/></svg>\n          <span>Roadmap operativa per la candidatura</span>\n        </div>\n      </div>\n    </div>\n  </aside>\n</section>\n\n<!-- ============ WHO WE ARE ============ -->\n<section class=\"bk-section bk-section--cream\">\n  <div class=\"bk-section__inner\">\n    <div class=\"bk-section__head\">\n      <div class=\"bk-section__num\">01 · Chi siamo</div>\n      <div class=\"bk-section__eyebrow\">Il team</div>\n      <h2 class=\"bk-section__title\">Tre professionisti.<br>Un'unica <span class=\"accent\">firma</span> sul tuo dossier.</h2>\n      <p class=\"bk-section__lede\">Non un call-center, non un network di freelance. Ogni progetto è seguito direttamente da uno di noi, dalla prima call fino alla rendicontazione finale.</p>\n    </div>\n\n    <div class=\"who-grid\">\n      <article class=\"who-card\">\n        <div class=\"who-card__avatar\"><img src=\"/team/maria.jpg\" alt=\"Maria Elena Oddo\"></div>\n        <h3 class=\"who-card__name\">Maria Elena Oddo</h3>\n        <div class=\"who-card__role\">EU Project Manager</div>\n        <p class=\"who-card__bio\">Oltre 10 anni di esperienza nella progettazione europea. Ex Presidente Giovani Imprenditori Sicindustria Palermo.</p>\n      </article>\n      <article class=\"who-card\">\n        <div class=\"who-card__avatar\"><img src=\"/team/alessandro.jpg\" alt=\"Alessandro Reina\"></div>\n        <h3 class=\"who-card__name\">Alessandro Reina</h3>\n        <div class=\"who-card__role\">Sviluppo territoriale</div>\n        <p class=\"who-card__bio\">Specialista in bandi pubblici, sistemi culturali e progetti complessi per la Pubblica Amministrazione.</p>\n      </article>\n      <article class=\"who-card\">\n        <div class=\"who-card__avatar\"><img src=\"/team/salvatore.jpg\" alt=\"Salvatore Ciacia\"></div>\n        <h3 class=\"who-card__name\">Salvatore Ciacia</h3>\n        <div class=\"who-card__role\">Mediatore creditizio OAM</div>\n        <p class=\"who-card__bio\">Ex Agente in Attività Finanziaria UniCredit. Operazioni di credito su misura per le imprese.</p>\n      </article>\n    </div>\n  </div>\n</section>\n\n<!-- ============ NEXT STEPS ============ -->\n<section class=\"bk-section bk-section--ink\">\n  <div class=\"bk-section__inner\">\n    <div class=\"bk-section__head\">\n      <div class=\"bk-section__num\">02 · Cosa succede dopo</div>\n      <div class=\"bk-section__eyebrow\">Il percorso</div>\n      <h2 class=\"bk-section__title\">Dalla call al <span class=\"accent\">saldo finale</span>.<br>Quattro passi, una sola firma.</h2>\n      <p class=\"bk-section__lede\">Nessun cliente lasciato a metà tra una fase e l'altra. Lo stesso EU Project Manager ti segue dalla diagnosi alla rendicontazione — con scadenze chiare e tempistiche concordate.</p>\n    </div>\n\n    <div class=\"steps\">\n      <div class=\"step\">\n        <div class=\"step__num\">01</div>\n        <div class=\"step__title\">Call di diagnosi</div>\n        <div class=\"step__desc\">30 minuti gratuiti per analizzare il tuo progetto e i bandi compatibili.</div>\n      </div>\n      <div class=\"step\">\n        <div class=\"step__num\">02</div>\n        <div class=\"step__title\">Proposta tecnica</div>\n        <div class=\"step__desc\">Roadmap operativa, tempistiche e stima del contributo ottenibile.</div>\n      </div>\n      <div class=\"step\">\n        <div class=\"step__num\">03</div>\n        <div class=\"step__title\">Candidatura</div>\n        <div class=\"step__desc\">Redigiamo il dossier completo secondo gli standard del bando scelto.</div>\n      </div>\n      <div class=\"step\">\n        <div class=\"step__num\">04</div>\n        <div class=\"step__title\">Gestione & rendiconto</div>\n        <div class=\"step__desc\">Ti seguiamo fino al saldo finale del contributo, senza lasciare nulla a metà.</div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FAQ ============ -->\n<section class=\"bk-section\">\n  <div class=\"bk-section__inner\">\n    <div class=\"bk-section__head\">\n      <div class=\"bk-section__num\">03 · Domande frequenti</div>\n      <div class=\"bk-section__eyebrow\">FAQ</div>\n      <h2 class=\"bk-section__title\">Le risposte alle domande<br>che ci ponete <span class=\"accent\">più spesso</span>.</h2>\n      <p class=\"bk-section__lede\">Non trovi quello che cerchi? Scrivici a <strong>info@euromedpartner.it</strong> — rispondiamo entro 24 ore lavorative.</p>\n    </div>\n\n    <div class=\"faq\">\n      <details open>\n        <summary>La call è davvero gratuita?</summary>\n        <div class=\"faq__answer\">Sì, la prima call di diagnosi è completamente gratuita e senza impegno. Serve a noi per capire se possiamo realmente aiutarti e a te per valutare se il nostro approccio fa al caso tuo.</div>\n      </details>\n      <details>\n        <summary>Quanto dura il processo di candidatura a un bando?</summary>\n        <div class=\"faq__answer\">Dipende dal bando e dalla complessità del progetto. Mediamente la redazione di un dossier completo richiede 4–8 settimane di lavoro congiunto. Per i progetti più articolati (PNRR, IPCEI, Horizon) può richiedere 3–4 mesi.</div>\n      </details>\n      <details>\n        <summary>Quanto costa il servizio se decido di proseguire?</summary>\n        <div class=\"faq__answer\">La nostra struttura tariffaria prevede una quota fissa di progettazione e una success fee al momento dell'ottenimento del contributo. Te lo spieghiamo in dettaglio in call, in totale trasparenza.</div>\n      </details>\n      <details>\n        <summary>Lavorate solo con imprese siciliane?</summary>\n        <div class=\"faq__answer\">La nostra sede operativa è a Palermo, ma supportiamo imprese su tutto il territorio nazionale e su programmi europei. Le opportunità di finanziamento per il Sud sono particolarmente vantaggiose, ma seguiamo progetti ovunque.</div>\n      </details>\n      <details>\n        <summary>Posso modificare le risposte del quiz?</summary>\n        <div class=\"faq__answer\">Sì. Puoi tornare indietro in qualsiasi momento dal pulsante in alto a sinistra. La diagnosi verrà ricalcolata automaticamente in base alle nuove risposte.</div>\n      </details>\n      <details>\n        <summary>Cosa succede se il mio progetto non è finanziabile?</summary>\n        <div class=\"faq__answer\">Te lo diciamo subito, in modo trasparente. In molti casi possiamo riorientare il progetto verso strumenti diversi (es. credito d'imposta, finanza d'impresa) o consigliarti come renderlo idoneo per un bando futuro.</div>\n      </details>\n    </div>\n  </div>\n</section>\n\n<!-- ============ REVIEWS ============ -->\n<section class=\"bk-section bk-section--cream\">\n  <div class=\"bk-section__inner\">\n    <div class=\"bk-section__head\">\n      <div class=\"bk-section__num\">04 · Recensioni</div>\n      <div class=\"bk-section__eyebrow\">Cosa dicono di noi</div>\n      <h2 class=\"bk-section__title\">Le parole di chi<br>ha già <span class=\"accent\">scelto</span> EuroMed Partner.</h2>\n    </div>\n\n    <div class=\"reviews-grid\">\n      <div class=\"review\">\n        <p class=\"review__quote\">Hanno saputo trasformare un'idea in un progetto finanziato. La trasparenza e la professionalità sono ciò che li distingue.</p>\n        <div class=\"review__attr\">\n          <strong>Giuseppe T.</strong>\n          CEO · PMI manifatturiera siciliana\n        </div>\n      </div>\n      <div class=\"review\">\n        <p class=\"review__quote\">Ci hanno seguiti passo passo dal pitch alla rendicontazione finale. Senza di loro non saremmo mai arrivati al closing.</p>\n        <div class=\"review__attr\">\n          <strong>Laura M.</strong>\n          Co-founder · start-up agritech\n        </div>\n      </div>\n      <div class=\"review\">\n        <p class=\"review__quote\">Approccio sobrio, niente promesse facili. Quando ti dicono che un progetto è finanziabile, è perché lo è davvero.</p>\n        <div class=\"review__attr\">\n          <strong>Marco D.</strong>\n          Sindaco · Comune dell'entroterra\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FINAL CTA ============ -->\n<section class=\"bk-final\">\n  <div class=\"bk-final__inner\">\n    <div class=\"bk-final__eyebrow\">Ci sei quasi</div>\n    <h2 class=\"bk-final__title\">Resta solo da scegliere<br>il tuo <span class=\"accent\">orario</span>.</h2>\n    <p class=\"bk-final__intro\">Trenta minuti per validare un'idea progettuale, capire quali bandi sono compatibili e definire i prossimi passi. Senza impegno.</p>\n    <a href=\"#cal\" class=\"btn btn--primary\">\n      Torna al calendario\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 19V5M5 12l7-7 7 7\"/></svg>\n    </a>\n    <p class=\"bk-final__sub\">Gratuito · 30 minuti · senza impegno</p>\n  </div>\n</section>\n\n<script>\n// ====== Calendar logic ======\n// Mock month: June 2026. Days 1 starts on a Monday.\nconst MONTH_LABEL = 'Giugno 2026';\nconst DAYS_IN_MONTH = 30;\nconst FIRST_DAY_OFFSET = 0; // Mon = 0 col in our ISO-style grid\nconst AVAILABLE_DAYS = [3, 4, 5, 9, 10, 11, 12, 16, 17, 18, 19, 23, 24, 25, 26];\nconst SLOTS_BY_DAY = {\n  default: ['09:00','09:30','10:00','11:00','11:30','14:00','15:00','15:30','16:00','16:30','17:00','17:30'],\n};\n\nconst daysEl = document.getElementById('calDays');\nconst slotsEl = document.getElementById('calSlots');\nconst slotsGridEl = document.getElementById('calSlotsGrid');\nconst slotsDateEl = document.getElementById('calSlotsDate');\nconst rowDate = document.getElementById('rowDate');\nconst confirmBtn = document.getElementById('confirmBtn');\n\nfunction renderDays(){\n  daysEl.innerHTML = '';\n  // Previous-month tail\n  for (let i = 0; i < FIRST_DAY_OFFSET; i++){\n    const d = document.createElement('div');\n    d.className = 'cal__day is-other';\n    d.textContent = '';\n    daysEl.appendChild(d);\n  }\n  for (let day = 1; day <= DAYS_IN_MONTH; day++){\n    const d = document.createElement('div');\n    d.className = 'cal__day';\n    d.textContent = day;\n    if (AVAILABLE_DAYS.includes(day)) d.classList.add('is-available');\n    else d.classList.add('is-disabled');\n    if (day === 5) d.classList.add('is-today');\n    d.dataset.day = day;\n    if (d.classList.contains('is-available')){\n      d.addEventListener('click', () => selectDay(day, d));\n    }\n    daysEl.appendChild(d);\n  }\n}\nfunction selectDay(day, el){\n  document.querySelectorAll('.cal__day.is-selected').forEach(n => n.classList.remove('is-selected'));\n  el.classList.add('is-selected');\n  slotsEl.style.display = 'block';\n  slotsDateEl.textContent = '';\n  slotsGridEl.innerHTML = '';\n  SLOTS_BY_DAY.default.forEach(t => {\n    const b = document.createElement('button');\n    b.className = 'cal__slot';\n    b.textContent = t;\n    b.addEventListener('click', () => selectSlot(day, t, b));\n    slotsGridEl.appendChild(b);\n  });\n  // Update sticky row\n  rowDate.querySelector('span').innerHTML = `<strong>${day} giugno 2026</strong>Seleziona orario`;\n}\nfunction selectSlot(day, t, el){\n  document.querySelectorAll('.cal__slot.is-selected,.cal__slot.is-confirmed').forEach(n => n.classList.remove('is-selected','is-confirmed'));\n  el.classList.add('is-selected');\n  rowDate.querySelector('span').innerHTML = `<strong>${day} giugno 2026 · ore ${t}</strong>Europe/Rome (CEST)`;\n  confirmBtn.textContent = 'Conferma ' + day + ' giugno · ' + t;\n  confirmBtn.dataset.armed = '1';\n  confirmBtn.addEventListener('click', confirmBooking, { once:true });\n}\nfunction confirmBooking(){\n  document.querySelectorAll('.cal__slot.is-selected').forEach(n => { n.classList.remove('is-selected'); n.classList.add('is-confirmed'); });\n  confirmBtn.textContent = '✓ Appuntamento confermato';\n  confirmBtn.style.background = '#2F7A4F';\n}\nrenderDays();\n</script>\n\n";
